            result.push_back(combination);
            return;
        }
        for (int i = start; i < data.size(); i++) {
            if (data[i] > target) continue;
            combination.push_back(data[i]);
            backtrack(result, combination, data, target - data[i], i); // allow same element
            combination.pop_back();
