package main

import "fmt"

type List [][]int

func combinationSum(data []int, target int) List {
    var result List
    var combination []int
    var backtrack func(start int, currentSum int)

    backtrack = func(start int, currentSum int) {
        if currentSum == target {
            combinationCopy := make([]int, len(combination))
            copy(combinationCopy, combination)
            result = append(result, combinationCopy)
            return
        }
        if currentSum > target {
            return
        }

        for i := start; i < len(data); i++ {
            combination = append(combination, data[i])
            backtrack(i, currentSum+data[i])
            combination = combination[:len(combination)-1]
        }
    }

    backtrack(0, 0)
    return result
}

func main() {
    data := []int{2, 3, 6, 7}
    target := 7
    result := combinationSum(data, target)
    fmt.Println(result)
}

