using System;
using System.Collections.Generic;

public class Solution {
    public List<List<int>> combinationSum(int[] data, int target) {
        List<List<int>> result = new List<List<int>>();
        List<int> combination = new List<int>();
        FindCombinations(data, target, 0, combination, result);
        return result;
    }

    private void FindCombinations(int[] data, int target, int start, List<int> combination, List<List<int>> result) {
        if (target == 0) {
            result.Add(new List<int>(combination));
            return;
        }
        for (int i = start; i < data.Length; i++) {
            if (data[i] > target) continue;
            combination.Add(data[i]);
            FindCombinations(data, target - data[i], i, combination, result);
            combination.RemoveAt(combination.Count - 1);
        }
    }
}

